-- ============================================
-- INITIALIZE PROGRESS FOR NEW CLEANERS
-- ============================================

CREATE OR REPLACE FUNCTION initialize_cleaner_level_progress()
RETURNS TRIGGER AS $$
BEGIN
  IF NEW.role = 'cleaner' THEN
    INSERT INTO cleaner_level_progress (cleaner_id, current_level)
    VALUES (NEW.id, 1)
    ON CONFLICT (cleaner_id) DO NOTHING;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trigger_initialize_level_progress ON users;
CREATE TRIGGER trigger_initialize_level_progress
  AFTER INSERT ON users
  FOR EACH ROW
  EXECUTE FUNCTION initialize_cleaner_level_progress();

-- Backfill existing cleaners
INSERT INTO cleaner_level_progress (cleaner_id, current_level)
SELECT cp.user_id, 1
FROM cleaner_profiles cp
WHERE NOT EXISTS (SELECT 1 FROM cleaner_level_progress lp WHERE lp.cleaner_id = cp.user_id)
ON CONFLICT (cleaner_id) DO NOTHING;

COMMENT ON TABLE cleaner_level_definitions IS 'Level 1-10 definitions for PureTask cleaner gamification';
COMMENT ON TABLE cleaner_level_goals IS 'Goals per level: core (required), stretch (1+ required), maintenance (ongoing)';
COMMENT ON TABLE cleaner_level_progress IS 'Per-cleaner level and progress';
COMMENT ON TABLE cleaner_goal_completions IS 'Tracks which goals each cleaner has completed';
COMMENT ON TABLE cleaner_rewards_granted IS 'Rewards awarded (cash, boosts, fee reductions)';
COMMENT ON TABLE cleaner_login_days IS 'Login streak tracking for daily login goals';
COMMENT ON TABLE cleaner_active_boosts IS 'Active visibility/ranking boosts';

SELECT 'Cleaner Level System Migration 043 Completed' AS status;


-- === 044_meaningful_login_and_attribution.sql ===
-- Migration 044: Meaningful login tracking + reward attribution placeholder
-- Enables "meaningful login" for streak goals (anti-gaming)
-- Prepares for reward attribution ("Your rewards helped you get +X bookings")

-- ============================================
-- MEANINGFUL ACTIONS (for login streak anti-gaming)
-- ============================================
-- A login counts as "meaningful" when the cleaner does one of:
--   accept/confirm job, send message, view job list + open details, upload photos
-- This table records such actions; login_streak goals can optionally require them.

CREATE TABLE IF NOT EXISTS cleaner_meaningful_actions (
  cleaner_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  action_date DATE NOT NULL,
  action_type TEXT NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (cleaner_id, action_date, action_type)
);

CREATE INDEX IF NOT EXISTS idx_meaningful_actions_cleaner ON cleaner_meaningful_actions(cleaner_id);
CREATE INDEX IF NOT EXISTS idx_meaningful_actions_date ON cleaner_meaningful_actions(action_date);

COMMENT ON TABLE cleaner_meaningful_actions IS 'Tracks meaningful actions for login streak anti-gaming';

-- ============================================
-- REWARD ATTRIBUTION (placeholder)
-- ============================================
-- Future: track when cleaners with active boosts get bookings, to show
-- "Your rewards helped you get +X extra bookings this week"
-- For now we add a view that can be extended later.

CREATE OR REPLACE VIEW cleaner_boost_attribution_placeholder AS
SELECT
  c.cleaner_id,
  DATE_TRUNC('week', NOW())::date AS week_start,
  0::int AS extra_bookings_attributed
FROM cleaner_active_boosts c
WHERE c.is_active = true AND c.expires_at > NOW()
GROUP BY c.cleaner_id;

COMMENT ON VIEW cleaner_boost_attribution_placeholder IS 'Placeholder for reward attribution; returns 0 until implemented';

SELECT 'Migration 044 Completed' AS status;


-- === 045_gamification_expansion.sql ===
-- Migration 045: Gamification expansion
-- Adds: good-faith declines, message templates, job add-ons, config support

-- ============================================
-- JOB ADD-ONS (for add-on completion goals)
-- ============================================
ALTER TABLE jobs ADD COLUMN IF NOT EXISTS has_addons BOOLEAN DEFAULT false;
ALTER TABLE jobs ADD COLUMN IF NOT EXISTS addons_count INTEGER DEFAULT 0;
COMMENT ON COLUMN jobs.has_addons IS 'Client selected add-ons at booking';
COMMENT ON COLUMN jobs.addons_count IS 'Number of add-ons selected at booking';

-- ============================================
-- MESSAGES: template_id for meaningful message rules
-- ============================================
ALTER TABLE messages ADD COLUMN IF NOT EXISTS template_id TEXT;
COMMENT ON COLUMN messages.template_id IS 'Quick template key if message sent via template (tmpl_thank_you, etc)';

-- ============================================
-- JOB OFFERS: decline reason for good-faith logic
-- ============================================
-- job_offers may have status declined; we need decline_reason
DO $$ BEGIN
  ALTER TABLE job_offers ADD COLUMN decline_reason TEXT;
EXCEPTION WHEN duplicate_column THEN NULL;
END $$;
COMMENT ON COLUMN job_offers.decline_reason IS 'Good-faith reason: distance_too_far, time_conflict, job_mismatch, safety_concern, access_logistics, too_short_notice';

-- ============================================
-- CLEANER: max travel for good-faith distance
-- ============================================
ALTER TABLE cleaner_profiles ADD COLUMN IF NOT EXISTS max_travel_miles NUMERIC(5,2) DEFAULT 10;
COMMENT ON COLUMN cleaner_profiles.max_travel_miles IS 'Max miles from home; job >= max+1 is good-faith decline';

-- ============================================
-- QUICK MESSAGE TEMPLATES (reference table)
-- ============================================
CREATE TABLE IF NOT EXISTS message_templates (
  id TEXT PRIMARY KEY,
  label TEXT NOT NULL,
  copy TEXT NOT NULL,
  category TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

